mapper.select:
SELECT vl.ID, vl.VISITOR_ID, vp.NICKNAME AS visitorNickname, vp.AVATAR AS visitorAvatar, vl.PATH, vl.TITLE, vl.REFERER, vl.TYPE, vl.IP, CONCAT(vl.COUNTRY, vl.PROVINCE, vl.CITY, vl.DISTRICT) AS ipRegion, vl.ISP, CONCAT(vl.BROWSER, vl.BROWSER_VERSION) AS BROWSER, vl.DEVICE_TYPE, vl.VISIT_TIME FROM visitor_log vl LEFT JOIN visitor_profile vp ON vp.VISITOR_ID = vl.VISITOR_ID
AND vl.VISITOR_ID = #{query.visitorId}
AND vl.IP = #{query.ip}
ORDER BY vl.VISIT_TIME DESC
